//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packageguarddutyimport("context""time""github.com/aws/aws-sdk-go/service/guardduty""github.com/hashicorp/terraform-plugin-sdk/v2/helper/retry")const(//MaximumamountoftimetowaitforanAdminAccounttoreturnEnabledadminAccountEnabledTimeout=5*time.Minute//MaximumamountoftimetowaitforanAdminAccounttoreturnNotFoundadminAccountNotFoundTimeout=5*time.Minute//MaximumamountoftimetowaitforaPublishingDestinationtoreturnPublishingpublishingDestinationCreatedTimeout=5*time.Minute//Maximumamountoftimetowaitformembershiptopropagate//WhenremovingOrganizationAdminAccounts,thereiseventual//consistencyevenaftertheaccountisnolongerlisted.//Referenceerrormessage://BadRequestException:Therequestisrejectedbecausethecurrentaccountcannotdeletedetectorwhileithasinvitedorassociatedmembers.membershipPropagationTimeout=2*time.Minute)//waitAdminAccountEnabledwaitsforanAdminAccounttoreturnEnabledfuncwaitAdminAccountEnabled(ctxcontext.Context,conn*guardduty.GuardDuty,adminAccountIDstring)(*guardduty.AdminAccount,error){stateConf:=&retry.StateChangeConf{Pending:[]string{adminStatusNotFound},Target:[]string{guardduty.AdminStatusEnabled},Refresh:statusAdminAccountAdmin(ctx,conn,adminAccountID),Timeout:adminAccountEnabledTimeout,}outputRaw,err:=stateConf.WaitForStateContext(ctx)ifoutput,ok:=outputRaw.(*guardduty.AdminAccount);ok{returnoutput,err}returnnil,err}//waitAdminAccountNotFoundwaitsforanAdminAccounttoreturnNotFoundfuncwaitAdminAccountNotFound(ctxcontext.Context,conn*guardduty.GuardDuty,adminAccountIDstring)(*guardduty.AdminAccount,error){stateConf:=&retry.StateChangeConf{Pending:[]string{guardduty.AdminStatusDisableInProgress},Target:[]string{adminStatusNotFound},Refresh:statusAdminAccountAdmin(ctx,conn,adminAccountID),Timeout:adminAccountNotFoundTimeout,}outputRaw,err:=stateConf.WaitForStateContext(ctx)ifoutput,ok:=outputRaw.(*guardduty.AdminAccount);ok{returnoutput,err}returnnil,err}//waitPublishingDestinationCreatedwaitsforGuardDutytoreturnPublishingfuncwaitPublishingDestinationCreated(ctxcontext.Context,conn*guardduty.GuardDuty,destinationID,detectorIDstring)(*guardduty.CreatePublishingDestinationOutput,error){stateConf:=&retry.StateChangeConf{Pending:[]string{guardduty.PublishingStatusPendingVerification},Target:[]string{guardduty.PublishingStatusPublishing},Refresh:statusPublishingDestination(ctx,conn,destinationID,detectorID),Timeout:publishingDestinationCreatedTimeout,}outputRaw,err:=stateConf.WaitForStateContext(ctx)ifv,ok:=outputRaw.(*guardduty.CreatePublishingDestinationOutput);ok{returnv,err}returnnil,err}